#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 0;

    int first_even_found = 0;
    int first_even = 0;
    int product = 0;
    int done = 0;

    for (int i = 0; i < n; i++) {
        int x;
        if (scanf("%d", &x) != 1) return 0;

        if (!first_even_found) {
            if (x % 2 == 0) {
                first_even_found = 1;
                first_even = x;
            }
        } else if (!done && x % 3 == 0) {
            product = first_even * x;
            done = 1;
        }
    }

    if (!done) printf("0\n");
    else printf("%d\n", product);

    return 0;
}

