#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 0;

    long long product = 1;
    int used = 0;

    for (int i = 0; i < n; i++) {
        int x;
        if (scanf("%d", &x) != 1) return 0;
        if (x >= -9 && x <= 9) {
            product *= x;
            used = 1;
        }
    }

    if (!used) printf("0\n");
    else printf("%lld\n", product);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 0;

    int prev, curr;
    if (scanf("%d", &prev) != 1) return 0;

    int diff = 0;
    for (int i = 1; i < n; i++) {
        if (scanf("%d", &curr) != 1) return 0;
        if (curr > prev) diff += 1;
        else if (curr < prev) diff -= 1;
        prev = curr;
    }

    printf("%d\n", diff);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 0;

    int found = 0;
    int best = 0;

    for (int i = 0; i < n; i++) {
        int x;
        if (scanf("%d", &x) != 1) return 0;
        if (x > 0 && x % 4 == 0) {
            if (!found || x < best) {
                best = x;
                found = 1;
            }
        }
    }

    if (!found) printf("-1\n");
    else printf("%d\n", best);

    return 0;
}

