#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 0;

    int cars = 0;
    for (int i = 0; i < n; i++) {
        int x;
        if (scanf("%d", &x) != 1) return 0;
        if (x == 1) cars++;
        else if (x == -1) {
            cars--;
            if (cars < 0) cars = 0;
        }
    }

    printf("%d\n", cars);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 0;

    int prime_count = 0, composite_count = 0;

    for (int i = 0; i < n; i++) {
        int x;
        if (scanf("%d", &x) != 1) return 0;

        if (x < 2) continue;

        int is_prime = 1;
        for (int d = 2; d * d <= x; d++) {
            if (x % d == 0) {
                is_prime = 0;
                break;
            }
        }

        if (is_prime) prime_count++;
        else composite_count++;
    }

    printf("%d\n", prime_count - composite_count);
    return 0;
}
